import com.netflix.hystrix.HystrixCommand;

public class GetMetadataCommand extends HystrixCommand<Metadata> {
  private final String key;
  public GetMetadataCommand(String key) {
    super(Setter.withGroupKey(...)
      .andCommandPropertiesDefaults(
        HystrixCommandProperties.Setter()
          .withExecutionTimeoutInMilliseconds(200)
          .withCircuitBreakerRequestVolumeThreshold(20)
          .withCircuitBreakerErrorThresholdPercentage(50)
      )
    );
    this.key = key;
  }

  @Override
  protected Metadata run() throws Exception {
    // protected call — maybe to Cassandra or partner service
    return remoteClient.fetch(key);
  }

  @Override
  protected Metadata getFallback() {
    // quick fallback: try cache, or return degraded default
    return localCache.get(key); // might be null / degraded
  }
}

