package main

// Minimal illustrative AppendEntries handler (Go-like pseudocode)
func AppendEntries(term int, leaderId string, prevLogIndex int, prevLogTerm int, entries []LogEntry, leaderCommit int) (int, bool) {
    // persistent state: currentTerm, log
    if term < currentTerm {
        return currentTerm, false
    }
    currentTerm = term
    leader = leaderId

    if !log.match(prevLogIndex, prevLogTerm) {
        return currentTerm, false
    }

    log.appendFrom(prevLogIndex+1, entries)

    if leaderCommit > commitIndex {
        commitIndex = min(leaderCommit, log.lastIndex())
        applyUpTo(commitIndex)
    }

    return currentTerm, true
}
